record_types.code:
type EHeader is record
  Task_Index : TRange;
  First : Eptr;
  Last : Eptr;
end record;

type Enode is record
  Task_Index : TRange;
  Next       : Eptr;
end record;

type General_Register (Special : Defs.Typen := Defs.NOTYP) is record
  I : Defs.HAC_Integer;
  case Special is
    when Defs.Floats     => R   : Defs.HAC_Float;
    when Defs.VStrings   => V   : HAT.VString;
    when Defs.Times      => Tim : Ada.Calendar.Time;
    when Defs.Durations  => Dur : Duration;
    when Defs.Text_Files => Txt : File_Ptr := Abstract_Console;
    when others          => null;
  end case;
end record;

type Interpreter_Data is record
  S                         : Stack_Type_Access;
  PS                        : Processor_State;
  IR                        : Order;
  CurTask                   : Integer;
  TCB                       : Task_Control_Blocks;
  Files                     : File_Vectors.Vector;
  Snap                      : Boolean;
  Nb_Callers                : Integer;
  Nb_Complete               : Integer;
  EList                     : Entry_Queue;
  TActive                   : TRange;
  Start_Time                : Ada.Calendar.Time;
  SWITCH                    : Boolean;
  SYSCLOCK                  : Ada.Calendar.Time;
  TIMER                     : Ada.Calendar.Time;
  Gen                       : Ada.Numerics.Float_Random.Generator;
  Scheduler                 : Scheduler_Type := Single_Task;
  Single_Task_Delay_Pending : Boolean        := False;
  feedback_tick             : Tick_Type;
end record;

type PriCB is record
  UPRI    : Integer;
  INHERIT : Boolean;
end record;

type Task_Control_Block is record
  T              : Defs.Index;
  B              : Defs.Index;
  PC             : Defs.Index;
  TS             : Task_State;
  InRendzv       : Integer;
  WAKETIME       : Ada.Calendar.Time;
  Pcontrol       : PriCB;
  QUANTUM        : Duration;
  LASTRUN        : Ada.Calendar.Time;
  DISPLAY        : Co_Defs.Display_Type;
  STACKSIZE      : Defs.Index;
  SUSPEND        : Integer;
  R1, R2, R3     : General_Register;
  R_Temp         : General_Register;
  Exception_Info : Exception_Propagation_Data;
end record;

subprograms.code:
procedure Allocate_Text_File (
  ND : in out Interpreter_Data;
  R  : in out General_Register
)

procedure Free_Allocated_Contents (
  ND         : in out Interpreter_Data;
  Open_Files :    out Open_Files_Vectors.Vector
)
